import { Route, Routes } from 'react-router-dom';
import './App.css';
import Home from './Pages/Home';
import Portofolios from './Pages/Portofolios';
import Abouts from './Pages/Abouts';
import Blogs from './Pages/Blogs';
import Contacts from './Pages/Contacts';
import Services from './Pages/Services';
import Layout from './components/Layout/Layout';

function App() {
  return (
    <div>
      <Routes>
        <Route element={<Layout />}>
          <Route path="/" element={<Home />}>HOME</Route>
          <Route path="/portofolio" element={<Portofolios />}>PORTOFOLIO</Route>
          <Route path="/about" element={<Abouts />}>ABOUT</Route>
          <Route path="/blog" element={<Blogs />}>BLOG</Route>
          <Route path="/contact" element={<Contacts />}>CONTACT</Route>
          <Route path="/service" element={<Services />}></Route>
        </Route>
      </Routes>
    </div>
  );
}

export default App;
